SELECT COUNT(*) AS total_awards
FROM awards
WHERE yearID = 2022;

SELECT COUNT(*) AS nomination_count
FROM nominations
WHERE awardID = (SELECT awardID FROM awards WHERE award_name = 'Manager of the Year' AND yearID = 2023);

SELECT COUNT(nominationID) AS total_nominations
FROM nominations
WHERE yearID = (SELECT yearID FROM award_year WHERE year = 2023);

SELECT DISTINCT p.player_name
FROM players p
JOIN nominations n ON p.playerID = n.playerID;
